// C# — Insertion Sort
int[] arr = { 5, 3, 8, 1, 2 };
int n = arr.Length;

for (int i = 1; i < n; i++)
{
    int key = arr[i];
    int j = i - 1;

    // shift elements greater than key one position to the right
    while (j >= 0 && arr[j] > key)
    {
        arr[j + 1] = arr[j];
        j--;
    }

    // insert key into its correct position
    arr[j + 1] = key;
}
// arr = { 1, 2, 3, 5, 8 }

// C++ — Insertion Sort
#include <iostream>
using namespace std;

void insertionSort(int arr[], int n) {
    for (int i = 1; i < n; i++) {
        int key = arr[i];
        int j = i - 1;
        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
}

